INSERT INTO "public"."certification_framework_requirements"
  ("id","framework_id","requirement_code","requirement_name","requirement_category","section","topic_area","description","order_index","max_points","is_mandatory","applicable_from_year","size_threshold")
VALUES
  ('a0e14001-0000-4000-8000-000000000001', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-4.1', 'Understand your organisation and its context', 'Context of the organisation', 'Context of the organisation', 'Context of the organisation', 'Identify the internal and external issues (commercial, regulatory, environmental conditions) that affect what your EMS needs to achieve.', 1, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000002', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-4.2', 'Identify interested parties and their needs', 'Context of the organisation', 'Context of the organisation', 'Context of the organisation', 'Determine who has a stake in your environmental performance (regulators, customers, community, employees) and which of their needs you treat as obligations.', 2, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000003', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-4.3', 'Define the scope of the EMS', 'Context of the organisation', 'Context of the organisation', 'Context of the organisation', 'Set and document the boundaries of the EMS — which sites, activities, products and services it applies to.', 3, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000004', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-4.4', 'Establish and maintain the EMS', 'Context of the organisation', 'Context of the organisation', 'Context of the organisation', 'Set up, run and continually improve the environmental management system and the processes within it.', 4, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000005', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-5.1', 'Top management leadership and commitment', 'Leadership', 'Leadership', 'Leadership', 'Senior leaders take accountability for the EMS, integrate it into business processes and provide the resources for it to work.', 5, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000006', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-5.2', 'Environmental policy', 'Leadership', 'Leadership', 'Leadership', 'Maintain a documented environmental policy that fits the organisation, commits to protecting the environment, meeting obligations and continual improvement, and is communicated.', 6, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000007', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-5.3', 'Roles, responsibilities and authorities', 'Leadership', 'Leadership', 'Leadership', 'Top management assigns and communicates who is responsible for which EMS duties.', 7, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000008', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-6.1.1', 'Plan to address risks and opportunities', 'Planning', 'Planning', 'Planning', 'Decide how you will identify and handle the risks and opportunities tied to your environmental aspects, compliance obligations and context.', 8, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000009', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-6.1.2', 'Identify environmental aspects and significance', 'Planning', 'Planning', 'Planning', 'Determine the environmental aspects of your activities, products and services that you can control or influence, and decide which are significant.', 9, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000010', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-6.1.3', 'Determine compliance obligations', 'Planning', 'Planning', 'Planning', 'Identify the legal requirements and other obligations relevant to your environmental aspects and how they apply to you.', 10, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000011', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-6.1.4', 'Plan actions for aspects, obligations and risks', 'Planning', 'Planning', 'Planning', 'Plan actions to address significant aspects, compliance obligations and risks, and integrate them into your processes.', 11, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000012', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-6.2', 'Environmental objectives and plans to meet them', 'Planning', 'Planning', 'Planning', 'Set measurable environmental objectives consistent with the policy, and plan what will be done, by whom, by when, and how results are evaluated.', 12, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000013', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-7.1', 'Resources for the EMS', 'Support', 'Support', 'Support', 'Determine and provide the people, infrastructure and resources needed to run and improve the EMS.', 13, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000014', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-7.2', 'Competence', 'Support', 'Support', 'Support', 'Ensure people whose work affects environmental performance are competent, and act to close competence gaps.', 14, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000015', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-7.3', 'Awareness', 'Support', 'Support', 'Support', 'Make sure staff are aware of the environmental policy, significant aspects, their EMS contribution and the consequences of not conforming.', 15, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000016', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-7.4', 'Communication', 'Support', 'Support', 'Support', 'Plan and carry out internal and external communications relevant to the EMS — what, when, with whom and how.', 16, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000017', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-7.5', 'Documented information', 'Support', 'Support', 'Support', 'Create, control and maintain the documents and records the EMS requires, including version, access and retention controls.', 17, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000018', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-8.1', 'Operational planning and control', 'Operation', 'Operation', 'Operation', 'Establish and control the operational processes needed to meet EMS requirements, including a lifecycle perspective and control over outsourced processes.', 18, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000019', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-8.2', 'Emergency preparedness and response', 'Operation', 'Operation', 'Operation', 'Identify potential environmental emergencies and prepare, test and review planned responses.', 19, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000020', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-9.1.1', 'Monitoring, measurement, analysis, evaluation', 'Performance evaluation', 'Performance evaluation', 'Performance evaluation', 'Decide what environmental performance to monitor and measure, with valid methods, and analyse and evaluate the results.', 20, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000021', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-9.1.2', 'Evaluation of compliance', 'Performance evaluation', 'Performance evaluation', 'Performance evaluation', 'Periodically evaluate whether you are meeting your compliance obligations and maintain knowledge of your compliance status.', 21, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000022', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-9.2', 'Internal audit', 'Performance evaluation', 'Performance evaluation', 'Performance evaluation', 'Run a planned programme of internal audits to check the EMS conforms and is effectively implemented.', 22, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000023', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-9.3', 'Management review', 'Performance evaluation', 'Performance evaluation', 'Performance evaluation', 'Top management periodically reviews the EMS using defined inputs (performance, audits, compliance, objectives) and records decisions and actions.', 23, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000024', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-10.1', 'Improvement (general)', 'Improvement', 'Improvement', 'Improvement', 'Determine opportunities for improvement and act on them to enhance environmental performance.', 24, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000025', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-10.2', 'Nonconformity and corrective action', 'Improvement', 'Improvement', 'Improvement', 'React to nonconformities, correct them, investigate root cause, take corrective action and check it worked.', 25, 1, true, 0, 'all'),
  ('a0e14001-0000-4000-8000-000000000026', '98d8efe8-9956-4461-967c-af2b2b838300', 'ISO14001-10.3', 'Continual improvement', 'Improvement', 'Improvement', 'Improvement', 'Continually improve the suitability, adequacy and effectiveness of the EMS to enhance environmental performance over time.', 26, 1, true, 0, 'all')
INSERT INTO "public"."certification_framework_requirements"
  ("id","framework_id","requirement_code","requirement_name","requirement_category","section","topic_area","description","order_index","max_points","is_mandatory","applicable_from_year","size_threshold")
VALUES
  ('a0e50001-0000-4000-8000-000000000001', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-4.1', 'Understand the organisation and its context', 'Context of the organisation', 'Context of the organisation', 'Context of the organisation', 'Identify the internal and external issues that affect the energy management system and your ability to improve energy performance.', 1, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000002', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-4.2', 'Needs of interested parties (incl. legal requirements)', 'Context of the organisation', 'Context of the organisation', 'Context of the organisation', 'Determine relevant interested parties, which of their needs become requirements, and capture applicable legal and other energy obligations.', 2, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000003', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-4.3', 'Define the EnMS scope and boundaries', 'Context of the organisation', 'Context of the organisation', 'Context of the organisation', 'Set out what the energy management system covers — facilities, activities and energy types inside its boundaries.', 3, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000004', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-4.4', 'Establish and maintain the EnMS', 'Context of the organisation', 'Context of the organisation', 'Context of the organisation', 'Put in place an energy management system that continually improves both the system and energy performance.', 4, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000005', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-5.1', 'Top management leadership and commitment', 'Leadership', 'Leadership', 'Leadership', 'Senior leaders own the EnMS, resource it, integrate energy performance into the business, and back the energy team.', 5, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000006', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-5.2', 'Energy policy', 'Leadership', 'Leadership', 'Leadership', 'Establish a documented energy policy committing to continual energy-performance improvement, legal compliance, and availability of information and resources.', 6, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000007', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-5.3', 'Roles, responsibilities and authorities', 'Leadership', 'Leadership', 'Leadership', 'Assign and communicate clear EnMS responsibilities, including who reports on energy performance to top management.', 7, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000008', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-6.1', 'Actions to address risks and opportunities', 'Planning', 'Planning', 'Planning', 'Identify risks and opportunities from the context and interested parties, and plan actions so the EnMS achieves its results.', 8, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000009', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-6.2', 'Objectives, energy targets and planning', 'Planning', 'Planning', 'Planning', 'Set energy objectives and measurable energy targets consistent with the policy, and plan how they will be achieved and evaluated.', 9, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000010', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-6.3', 'Energy review', 'Planning', 'Planning', 'Planning', 'Carry out and maintain a structured analysis of energy use, identify significant energy uses (SEUs) and the factors affecting them, and find improvement opportunities.', 10, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000011', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-6.4', 'Energy performance indicators (EnPIs)', 'Planning', 'Planning', 'Planning', 'Determine EnPIs that let you measure and demonstrate energy-performance improvement, and review them against the baseline.', 11, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000012', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-6.5', 'Energy baseline (EnB)', 'Planning', 'Planning', 'Planning', 'Establish energy baselines using a suitable reference period against which energy-performance changes are measured, and maintain them.', 12, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000013', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-6.6', 'Planning for collection of energy data', 'Planning', 'Planning', 'Planning', 'Define a plan for collecting the energy data needed to manage performance — variables, SEUs, meters and accuracy.', 13, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000014', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-7.1', 'Resources', 'Support', 'Support', 'Support', 'Determine and provide the people, infrastructure and resources needed to establish, maintain and improve the EnMS.', 14, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000015', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-7.2', 'Competence', 'Support', 'Support', 'Support', 'Ensure people whose work affects energy performance are competent, and keep evidence of this.', 15, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000016', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-7.3', 'Awareness', 'Support', 'Support', 'Support', 'Make sure people under your control are aware of the energy policy, their contribution to energy performance, and the benefits of improvement.', 16, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000017', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-7.4', 'Communication', 'Support', 'Support', 'Support', 'Determine internal and external EnMS communications and provide a way for staff to suggest energy improvements.', 17, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000018', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-7.5', 'Documented information', 'Support', 'Support', 'Support', 'Create, control and maintain the documented information required, with proper version, access and retention control.', 18, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000019', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-8.1', 'Operational planning and control', 'Operation', 'Operation', 'Operation', 'Plan, implement and control operations linked to significant energy uses, set operating criteria, and control planned changes.', 19, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000020', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-8.2', 'Design', 'Operation', 'Operation', 'Operation', 'Consider energy-performance improvement and operational control in the design of new or modified facilities, equipment and processes.', 20, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000021', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-8.3', 'Procurement', 'Operation', 'Operation', 'Operation', 'Where procurement significantly affects energy performance, set energy criteria for purchases and inform suppliers that energy matters.', 21, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000022', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-9.1', 'Monitoring & evaluation of energy performance', 'Performance evaluation', 'Performance evaluation', 'Performance evaluation', 'Monitor and measure EnPIs, SEUs, action-plan progress and actual vs expected consumption, and act on significant deviations.', 22, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000023', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-9.1c', 'Evaluation of compliance with legal requirements', 'Performance evaluation', 'Performance evaluation', 'Performance evaluation', 'Evaluate, at planned intervals, whether you comply with legal and other energy requirements, and keep records.', 23, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000024', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-9.2', 'Internal audit', 'Performance evaluation', 'Performance evaluation', 'Performance evaluation', 'Run internal audits at planned intervals to check the EnMS conforms and is effectively implemented, using competent, impartial auditors.', 24, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000025', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-9.3', 'Management review', 'Performance evaluation', 'Performance evaluation', 'Performance evaluation', 'Top management reviews the EnMS against defined inputs (energy performance, EnPIs, objectives, actions) and records decisions.', 25, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000026', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-10.1', 'Nonconformity and corrective action', 'Improvement', 'Improvement', 'Improvement', 'React to nonconformities, correct them, remove their cause through corrective action, and verify the action worked.', 26, 1, true, 0, 'all'),
  ('a0e50001-0000-4000-8000-000000000027', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ISO50001-10.2', 'Continual improvement', 'Improvement', 'Improvement', 'Improvement', 'Continually improve the EnMS and demonstrate continual improvement of energy performance over time.', 27, 1, true, 0, 'all')
INSERT INTO "public"."certification_framework_requirements"
  ("id","framework_id","requirement_code","requirement_name","requirement_category","section","topic_area","description","order_index","max_points","is_mandatory","applicable_from_year","size_threshold")
VALUES
  ('a0ec0d15-0000-4000-8000-000000000001', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ENV-01', 'Energy use & greenhouse gas emissions', 'Environment', 'Environment', 'Environment', 'How you manage energy and your carbon footprint across Scopes 1–3: the policy commitment, reduction measures, and the measured trend over time.', 1, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000002', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ENV-02', 'Water management', 'Environment', 'Environment', 'Environment', 'How you monitor and reduce water consumption and protect water quality: policy, efficiency actions, and reported consumption.', 2, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000003', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ENV-03', 'Biodiversity & land use', 'Environment', 'Environment', 'Environment', 'Impacts on ecosystems, habitats and land from operations and sourcing: biodiversity policy, protective/restorative actions, and monitored outcomes.', 3, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000004', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ENV-04', 'Local & accidental pollution', 'Environment', 'Environment', 'Environment', 'Control of air, soil and water pollution and prevention of spills/accidental releases: prevention policy, controls, and incident results.', 4, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000005', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ENV-05', 'Materials, chemicals & waste', 'Environment', 'Environment', 'Environment', 'Responsible use of materials and chemicals and how waste is reduced, reused or recycled: policy, circularity actions, and waste/recycling metrics.', 5, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000006', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ENV-06', 'Product use impacts', 'Environment', 'Environment', 'Environment', 'The environmental footprint of products in the customer-use phase and efforts to design lower-impact products.', 6, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000007', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ENV-07', 'Product end-of-life', 'Environment', 'Environment', 'Environment', 'How products and packaging are managed at disposal — recyclability, take-back and end-of-life design.', 7, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000008', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-LAB-01', 'Employee health & safety', 'Labour & Human Rights', 'Labour & Human Rights', 'Labour & Human Rights', 'How you protect worker health and safety on site: the H&S policy, prevention/training measures, and incident-rate results.', 8, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000009', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-LAB-02', 'Working conditions', 'Labour & Human Rights', 'Labour & Human Rights', 'Labour & Human Rights', 'Pay, working hours, benefits and overall job quality: policy, wage/benefit actions, and results such as living-wage coverage.', 9, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000010', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-LAB-03', 'Social dialogue & employee engagement', 'Labour & Human Rights', 'Labour & Human Rights', 'Labour & Human Rights', 'Worker representation, collective bargaining and engagement: policy on freedom of association, dialogue actions, and engagement results.', 10, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000011', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-LAB-04', 'Career management & training', 'Labour & Human Rights', 'Labour & Human Rights', 'Labour & Human Rights', 'Investment in employee skills, training and development: policy, development actions, and training-hour/coverage results.', 11, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000012', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-LAB-05', 'Child labour, forced labour & trafficking', 'Labour & Human Rights', 'Labour & Human Rights', 'Labour & Human Rights', 'Safeguards against child labour, forced labour and trafficking in operations and supply chain: prohibition policy, due-diligence, and monitoring.', 12, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000013', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-LAB-06', 'Diversity, discrimination & harassment', 'Labour & Human Rights', 'Labour & Human Rights', 'Labour & Human Rights', 'Anti-discrimination protections and promotion of diversity, equity and inclusion: policy, grievance/inclusion actions, and diversity metrics.', 13, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000014', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-LAB-07', 'External stakeholders'' human rights', 'Labour & Human Rights', 'Labour & Human Rights', 'Labour & Human Rights', 'Respect for the human rights of communities and people outside the workforce affected by operations.', 14, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000015', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-LAB-08', 'Fundamental human rights', 'Labour & Human Rights', 'Labour & Human Rights', 'Labour & Human Rights', 'Your overarching commitment to internationally recognised human rights and your due-diligence process.', 15, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000016', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ETH-01', 'Anti-corruption & bribery', 'Ethics', 'Ethics', 'Ethics', 'Prevention of corruption, bribery and fraud: policy, control/training actions, and outcomes such as incidents and audit coverage.', 16, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000017', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ETH-02', 'Anticompetitive practices', 'Ethics', 'Ethics', 'Ethics', 'Safeguards against anti-competitive behaviour such as price-fixing and abuse of market position: policy, training, and results.', 17, 1, true, 0, 'all'),
  ('a0ec0d15-0000-4000-8000-000000000018', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9', 'ECOVADIS-ETH-03', 'Responsible information management', 'Ethics', 'Ethics', 'Ethics', 'Protection of data, privacy and information security, including customer and employee data: policy, security actions, and breach results.', 18, 1, true, 0, 'all'),
