-- ISO 14001, ISO 50001 and EcoVadis requirement sets.
-- Paraphrased from public clause/criteria structure (no copyrighted text).
-- Generated from lib/certifications/frameworks/*. Idempotent.

-- ISO 14001 (iso14001) — 26 requirements
ON CONFLICT ("id") DO UPDATE SET
  "requirement_name" = EXCLUDED."requirement_name",
  "requirement_category" = EXCLUDED."requirement_category",
  "topic_area" = EXCLUDED."topic_area",
  "description" = EXCLUDED."description",
  "order_index" = EXCLUDED."order_index";

-- ISO 50001 (iso50001) — 27 requirements
ON CONFLICT ("id") DO UPDATE SET
  "requirement_name" = EXCLUDED."requirement_name",
  "requirement_category" = EXCLUDED."requirement_category",
  "topic_area" = EXCLUDED."topic_area",
  "description" = EXCLUDED."description",
  "order_index" = EXCLUDED."order_index";

-- EcoVadis (ecovadis) — 21 requirements
ON CONFLICT ("id") DO UPDATE SET
  "requirement_name" = EXCLUDED."requirement_name",
  "requirement_category" = EXCLUDED."requirement_category",
  "topic_area" = EXCLUDED."topic_area",
  "description" = EXCLUDED."description",
  "order_index" = EXCLUDED."order_index";

-- Sync into framework_requirements with the same ids.
SELECT cfr."id", cfr."framework_id", cfr."requirement_code", cfr."requirement_name", cfr."requirement_category", cfr."section", cfr."subsection", cfr."order_index", cfr."description", cfr."guidance", cfr."max_points", cfr."is_mandatory", cfr."is_conditional", cfr."required_data_sources", cfr."evidence_requirements", cfr."applicable_from_year", cfr."size_threshold", cfr."topic_area", cfr."created_at", cfr."updated_at"
FROM "public"."certification_framework_requirements" cfr
WHERE cfr."framework_id" IN ('98d8efe8-9956-4461-967c-af2b2b838300', '53ac5afb-a3b7-4956-a07d-42079798dae7', 'ccc5d243-19c5-4205-aeb6-bd495ce444d9')
ON CONFLICT ("id") DO NOTHING;
